const item = $input.first().json;
const root = item.body || item;
const apiResponse = root.data || root;

if (!apiResponse || !apiResponse.seriesLabels || !apiResponse.series) {
  return [{ json: { error: "No WAU chart data found" } }];
}

const companies = apiResponse.seriesLabels;
const seriesData = apiResponse.series;
const xValues    = apiResponse.xValues || [];

// ─────────────────────────────────────────────
// Detect if last weekly bucket is a partial week
// ─────────────────────────────────────────────
let wau_is_partial_week = false;
let wau_days_covered    = 7;
let wau_week_start_date = null;

if (xValues.length > 0) {
  const lastXStr  = xValues[xValues.length - 1];        // e.g. "2026-02-23"
  const weekStart = new Date(lastXStr + "T00:00:00Z");
  const weekEnd   = new Date(weekStart);
  weekEnd.setUTCDate(weekStart.getUTCDate() + 7);

  wau_week_start_date = lastXStr;

  const nowUtc = new Date();
  if (nowUtc < weekEnd) {
    wau_is_partial_week = true;
    const daysElapsed = Math.floor((nowUtc - weekStart) / (1000 * 60 * 60 * 24));
    wau_days_covered   = Math.max(1, daysElapsed + 1); // Mon=1, Tue=2 ...
  }
}

const results = [];

for (let i = 0; i < companies.length; i++) {
  const label = companies[i];

  // ✅ Find first string in [0, "Company Name"]
  let companyName;
  if (Array.isArray(label)) {
    companyName = label.find(v => typeof v === 'string') ?? null;
  } else {
    companyName = label;
  }

  if (!companyName || companyName === '(none)') continue;

  const dataPoints = seriesData[i] || [];
  const len        = dataPoints.length;

  // ─────────────────────────────────────────────
  // Rolling weekly buckets (newest → oldest)
  // w1 = current/last week (may be partial)
  // w2 = 1 week ago, w3 = 2 weeks ago, w4 = 3 weeks ago
  // ─────────────────────────────────────────────
  const w1 = len > 0 ? (dataPoints[len - 1]?.value ?? null) : null;
  const w2 = len > 1 ? (dataPoints[len - 2]?.value ?? null) : null;
  const w3 = len > 2 ? (dataPoints[len - 3]?.value ?? null) : null;
  const w4 = len > 3 ? (dataPoints[len - 4]?.value ?? null) : null;

  // Rolling window sums — null if any required component is missing
  const WAU_last_7d  = w1;
  const WAU_last_14d = w1 != null && w2 != null ? w1 + w2 : null;
  const WAU_last_21d = w1 != null && w2 != null && w3 != null ? w1 + w2 + w3 : null;
  const WAU_last_28d = w1 != null && w2 != null && w3 != null && w4 != null
    ? w1 + w2 + w3 + w4 : null;

  // ─────────────────────────────────────────────
  // Partial week projections for current week (w1)
  // ─────────────────────────────────────────────
  const WAU_projected = (w1 != null && wau_days_covered > 0)
    ? Math.round((w1 / wau_days_covered) * 7)
    : null;

  const WAU_daily_avg = (w1 != null && wau_days_covered > 0)
    ? parseFloat((w1 / wau_days_covered).toFixed(2))
    : null;

  // Adjusted last_14d/21d/28d using projected w1 for fairer comparison
  const WAU_last_14d_projected = (WAU_projected != null && w2 != null)
    ? WAU_projected + w2 : null;
  const WAU_last_21d_projected = (WAU_projected != null && w2 != null && w3 != null)
    ? WAU_projected + w2 + w3 : null;
  const WAU_last_28d_projected = (WAU_projected != null && w2 != null && w3 != null && w4 != null)
    ? WAU_projected + w2 + w3 + w4 : null;

  results.push({
    json: {
      company_name: companyName,

      // ── CURRENT WEEK (w1, may be partial) ──
      WAU:                  w1,               // raw count so far this week
      WAU_days_covered:     wau_days_covered, // how many days are in w1
      WAU_is_partial_week:  wau_is_partial_week,
      WAU_projected,                          // full-week projection for w1
      WAU_daily_avg,                          // daily pace this week
      wau_week_start_date,

      // ── ROLLING WINDOWS (raw) ──
      WAU_last_7d,   // = w1 (current week raw)
      WAU_last_14d,  // = w1 + w2
      WAU_last_21d,  // = w1 + w2 + w3
      WAU_last_28d,  // = w1 + w2 + w3 + w4

      // ── ROLLING WINDOWS (projected) ──
      // Replaces partial w1 with projected full-week value
      // Use these when is_partial_week = true for fair threshold checks
      WAU_last_14d_projected,
      WAU_last_21d_projected,
      WAU_last_28d_projected
    }
  });
}

return results;

const item = $input.first().json;
const apiResponse = item.body ? item.body.data : item.data;

if (!apiResponse || !apiResponse.seriesLabels || !apiResponse.series) {
  return [{ json: { error: "No MAU chart data found" } }];
}

const companies = apiResponse.seriesLabels;
const seriesData = apiResponse.series;
const xValues    = apiResponse.xValues || [];

// ─────────────────────────────────────────────
// MONTHLY buckets — detect partial month
// Last xValue = "2026-02-01" → Feb 2026
// ─────────────────────────────────────────────
let mau_is_partial_month = false;
let mau_days_covered     = 31;
let mau_days_in_month    = 31;
let mau_month_start_date = null;

if (xValues.length > 0) {
  const lastXStr       = xValues[xValues.length - 1];      // "2026-02-01"
  mau_month_start_date = lastXStr;

  const monthStart  = new Date(lastXStr + "T00:00:00Z");
  const year        = monthStart.getUTCFullYear();
  const month       = monthStart.getUTCMonth();             // 0-indexed

  // Exact days in this month (handles Feb 28/29, 30/31 month variations)
  mau_days_in_month = new Date(Date.UTC(year, month + 1, 0)).getUTCDate();

  const monthEnd = new Date(Date.UTC(year, month + 1, 1)); // 1st of next month

  const nowUtc = new Date();
  if (nowUtc < monthEnd) {
    mau_is_partial_month = true;
    const daysElapsed = Math.floor((nowUtc - monthStart) / (1000 * 60 * 60 * 24));
    mau_days_covered   = Math.max(1, daysElapsed + 1);      // Feb 1=1, Feb 24=24...
  } else {
    mau_days_covered = mau_days_in_month;
  }
}

const results = [];

for (let i = 0; i < companies.length; i++) {
  const label = companies[i];

  // ✅ Plain strings (like Forms) — but handles arrays gracefully too
  let companyName;
  if (Array.isArray(label)) {
    companyName = label.find(v => typeof v === 'string') ?? null;
  } else {
    companyName = typeof label === 'string' ? label : null;
  }

  if (!companyName || companyName === '(none)') continue;

  const dataPoints = seriesData[i] || [];
  const len        = dataPoints.length;

  // ─────────────────────────────────────────────
  // Monthly rolling buckets (newest → oldest)
  // w1 = current month (may be partial)
  // w2 = last month, w3 = 2 months ago, w4 = 3 months ago
  // ─────────────────────────────────────────────
  const w1 = len > 0 ? (dataPoints[len - 1]?.value ?? null) : null;
  const w2 = len > 1 ? (dataPoints[len - 2]?.value ?? null) : null;
  const w3 = len > 2 ? (dataPoints[len - 3]?.value ?? null) : null;
  const w4 = len > 3 ? (dataPoints[len - 4]?.value ?? null) : null;

  // Rolling window sums — null if any required component is missing
  const MAU_last_1m = w1;
  const MAU_last_2m = w1 != null && w2 != null ? w1 + w2 : null;
  const MAU_last_3m = w1 != null && w2 != null && w3 != null
    ? w1 + w2 + w3 : null;
  const MAU_last_4m = w1 != null && w2 != null && w3 != null && w4 != null
    ? w1 + w2 + w3 + w4 : null;

  // ─────────────────────────────────────────────
  // Partial month projections
  // Project w1 to full month at current daily pace
  // ─────────────────────────────────────────────
  const MAU_projected = (w1 != null && mau_days_covered > 0)
    ? Math.round((w1 / mau_days_covered) * mau_days_in_month)
    : null;

  const MAU_daily_avg = (w1 != null && mau_days_covered > 0)
    ? parseFloat((w1 / mau_days_covered).toFixed(2))
    : null;

  // Projected rolling windows — use projected w1 for fair threshold checks
  const MAU_last_2m_projected = (MAU_projected != null && w2 != null)
    ? MAU_projected + w2 : null;
  const MAU_last_3m_projected = (MAU_projected != null && w2 != null && w3 != null)
    ? MAU_projected + w2 + w3 : null;
  const MAU_last_4m_projected = (MAU_projected != null && w2 != null && w3 != null && w4 != null)
    ? MAU_projected + w2 + w3 + w4 : null;

  results.push({
    json: {
      company_name: companyName,

      // ── CURRENT MONTH (w1, may be partial) ──
      monthly_active_users:  w1,                    // raw MAU so far this month
      MAU_days_covered:      mau_days_covered,       // e.g. 24 (Feb 1–24)
      MAU_days_in_month:     mau_days_in_month,      // e.g. 28 (Feb 2026)
      MAU_is_partial_month:  mau_is_partial_month,   // true if month ongoing
      MAU_projected,                                 // full-month projection
      MAU_daily_avg,                                 // daily pace this month
      mau_month_start_date,                          // "2026-02-01"

      // ── ROLLING WINDOWS (raw) ──
      MAU_last_1m,   // = w1 (this month raw)
      MAU_last_2m,   // = w1 + w2
      MAU_last_3m,   // = w1 + w2 + w3
      MAU_last_4m,   // = w1 + w2 + w3 + w4

      // ── ROLLING WINDOWS (projected) ──
      // Replaces partial w1 with projected full-month value
      // Use these when MAU_is_partial_month = true
      MAU_last_2m_projected,
      MAU_last_3m_projected,
      MAU_last_4m_projected
    }
  });
}

return results;

