// ══════════════════════════════════════════════════════
// Code in JavaScript4 — HubSpot + Amplitude Combiner
// Mode: Run Once for All Items
// ══════════════════════════════════════════════════════

// ── Safe number helper (Defaults to 0 for math fields) ──
const num = (v, fallback = 0) =>
  (v != null && v !== '' && !isNaN(Number(v)) ? Number(v) : fallback);

// ── 1. Get HubSpot response ──
const allInputs = $input.all();
if (!allInputs || allInputs.length === 0) {
  return [{ json: { error: 'No input data', skipai: true } }];
}

const hubspotResponse = allInputs[0].json;
const results = hubspotResponse.results || [];

// ── 2. Get Amplitude Data Directly from the Loop ──
let amp = null;
try {
  // ✅ FIX: Use .first() instead of .item because the node is in "Run Once for All Items" mode.
  // Since the loop processes 1 item at a time, .first() safely grabs the current Amplitude record.
  amp = $('Loop Over Items').first().json;
} catch(e) {}

const ampCompanyName = amp ? amp.company_name : null;

const hubspotData = results.length > 0 ? results[0] : null;
const props = hubspotData ? hubspotData.properties : {};

// HubSpot name takes priority, fallback to Amplitude name
const companyName = props.name || ampCompanyName || "Unknown Company";

if (results.length === 0) {
  return [{
    json: {
      error: 'Company not found in HubSpot',
      skipai: true,
      company_name: companyName,
    }
  }];
}

// ── Lifecycle filter ──
const rawStage = (props.caddy_lifecycle_stage || '').trim();
if (rawStage.toLowerCase() !== 'live customer') {
  return [{
    json: {
      error: `Skipped — lifecycle stage: "${rawStage || 'unknown'}"`,
      skipai: true,
      companyid: hubspotData.id || "MISSING_ID",
      company_name: companyName,
    }
  }];
}

// ── Timezone Resolution ──
let accounttimezone = props.timezone || null;
if (!accounttimezone || typeof accounttimezone !== 'string' || !accounttimezone.includes('/')) {
  accounttimezone = 'America/New_York';
}

if (!amp) amp = {};

// ── 5. Build FULL output ──
return [{
  json: {

    companyid: hubspotData.id || "MISSING_ID",
    company_name: companyName,
    domain: props.domain || null,
    accounttimezone,

    lifecyclestage: props.caddy_lifecycle_stage || 'Live Customer',
    onboardingphase: props.onboarding_phase || 'Completed',
    slatier: props.sla_tier || 'Basic',
    supporttier: props.support_tier || 'Standard',

    // ✅ Paid Seats defaults to 1
    paidseats: num(props.seats, 1),

    // ✅ Strings default correctly
    churnriskscoreprev: num(props.churn_risk_score),
    churnriskreasonprev: props.churn_risk_reason || "None",

    forms_last_7d: num(amp.forms_last_7d),
    forms_last_14d: num(amp.forms_last_14d),
    forms_last_21d: num(amp.forms_last_21d),
    forms_last_28d: num(amp.forms_last_28d),
    forms_7d_projected: num(amp.forms_7d_projected),
    forms_last_14d_projected: num(amp.forms_last_14d_projected),
    forms_last_21d_projected: num(amp.forms_last_21d_projected),
    forms_last_28d_projected: num(amp.forms_last_28d_projected),

    // ✅ Booleans default to false, Dates default to null
    forms_is_partial_week: amp.forms_is_partial_week ?? false,
    forms_days_covered: num(amp.forms_days_covered),
    forms_daily_avg: num(amp.forms_daily_avg),
    forms_week_start_date: amp.forms_week_start_date ?? null,
