const clean = (value) => {
  if (typeof value === 'string') return value.replace(/[\x00-\x1F]/g, '');
  if (Array.isArray(value))      return value.map(clean);
  if (value && typeof value === 'object') {
    const out = {};
    for (const k of Object.keys(value)) out[k] = clean(value[k]);
    return out;
  }
  return value;
};

// ─── 3. Map Fields and Sanitise (Final Output Generation) ───
return [...seen.values()].map(item => {
  const data = clean(item.json);

