  const row = item.json;

  // Must be pending >7 days AND notificationstatus != Escalated
  const createdAt = new Date(row.createdAt || row.createdat || 0).getTime();
  const isPending7d = (now - createdAt) > (7 * 24 * 60 * 60 * 1000); // 7 days ms
  const notEscalated = (row.notificationstatus || row.notificationstatus === null || '').trim() !== 'Escalated';

  if (!isPending7d || !notEscalated) return false;

  // At-risk conditions (any of these)
  const health = (row.health_status || row.healthstatus || '').trim();
  const isPoorHealth = health === 'Poor Health';
