const item = $input.item;
const data = item.json || {};

const tz = data.accounttimezone || 'America/New_York';
const nowUtc = new Date();

let localTime;
try {
  localTime = new Date(nowUtc.toLocaleString('en-US', { timeZone: tz }));
} catch (e) {
  localTime = new Date(nowUtc.toLocaleString('en-US', { timeZone: 'America/New_York' }));
}

const weekdayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const localWeekday = weekdayNames[localTime.getDay()];
const localHour = localTime.getHours();
const localMinute = localTime.getMinutes();

const isWeekend = (localWeekday === 'Sat' || localWeekday === 'Sun');
const isPreferredDay = ['Tue', 'Wed', 'Thu'].includes(localWeekday);
const isPreferredHour = (localHour >= 9 && localHour < 11);
const canSendNow = !isWeekend;
const sendWindowPreferred = isPreferredDay && isPreferredHour;

const timeStr = `${String(localHour).padStart(2, '0')}:${String(localMinute).padStart(2, '0')}`;
let sendWindowCheck;
if (isWeekend) {
  sendWindowCheck = `${localWeekday} ${timeStr} ${tz} — weekend, email held`;
} else if (sendWindowPreferred) {
  sendWindowCheck = `${localWeekday} ${timeStr} ${tz} — within preferred window`;
} else {
  sendWindowCheck = `${localWeekday} ${timeStr} ${tz} — weekday, outside preferred hours`;
}

item.json = {
  ...data,
  isweekend: isWeekend,
  cansendnow: canSendNow,
  sendwindowpreferred: sendWindowPreferred,
  sendwindowcheck: sendWindowCheck,
  localtimecomputed: nowUtc.toISOString(),
};

return item;

