const results = [];
const raw = $input.item.json;

const outputArr = raw.output ?? (Array.isArray(raw) ? raw : null);
if (!outputArr || !Array.isArray(outputArr)) {
  return [{ json: { error: 'No output array found', raw } }];
}

for (const msg of outputArr) {
  if (msg.type !== 'message' || msg.status !== 'completed') {}
  else {
    const contentArr = msg.content ?? [];
    for (const block of contentArr) {
      if (block.type !== 'output_text') {}
      else {
        const text = block.text;
        if (!text || typeof text !== 'object') {}
        else {
          const outreach = text.outreach     ?? {};
          const data     = text.datatablerow ?? text.data_table_row ?? {};

          const now   = new Date().toISOString();
          const fixTs = (ts) => (!ts || new Date(ts).getUTCFullYear() < 2025) ? now : ts;

          const action = (data.action ?? 'NOACTION')
            .trim().toUpperCase()
            .replace('AI_OUTREACH',     'AIOUTREACH')
            .replace('ESCALATE_TO_RON', 'ESCALATETORON')
            .replace('NO_ACTION',       'NOACTION');

          const email     = data.Email ?? data.primarycontactemail ?? null;
          const emailSent = outreach.emailsent === true;
          const hasEmail  = !!(email && email.trim().length > 0);

          let notificationstatus, outreachoutcome;
          if (action === 'ESCALATETORON') {
            notificationstatus = 'Escalated';
            outreachoutcome    = 'Needs Human';
          } else if (action === 'AIOUTREACH' && emailSent) {
            notificationstatus = 'Sent';
            outreachoutcome    = 'Pending';
          } else if (action === 'AIOUTREACH' && !emailSent && hasEmail) {
            notificationstatus = 'Pending';
            outreachoutcome    = 'Pending';
          } else if (action === 'AIOUTREACH' && !emailSent && !hasEmail) {
            notificationstatus = 'Pending - No Email';
            outreachoutcome    = 'Pending - No Email';
          } else {
            notificationstatus = 'None';
            outreachoutcome    = 'None';
          }

          results.push({
            json: {
              userid:                 data.userid      ?? null,
              companyname:            data.companyname ?? data.company_name ?? null,
              Email:                  email,
              healthstatus:           data.healthstatus ?? null,
              healthscore:            data.healthscore  ?? null,
              riskscore:              data.riskscore    ?? null,
              reasoning:              data.reasoning    ?? null,
              action,
              notificationstatus,
              outreachoutcome,
              timestamp:              fixTs(outreach.timestamp),
              observationwindowstart: action !== 'NOACTION' ? fixTs(data.observationwindowstart) : null,
              lastoutreachdate:       emailSent ? fixTs(data.lastoutreachdate) : null,
              escalationdate:         action === 'ESCALATETORON' ? fixTs(data.escalationdate) : null,
              accounttimezone:        data.accounttimezone ?? null,
              slatier:                data.slatier         ?? null,
              isweekend:              raw.isweekend          ?? false,
              cansendnow:             raw.cansendnow         ?? false,
              sendwindowpreferred:    raw.sendwindowpreferred ?? false,
              sendwindowcheck:        raw.sendwindowcheck     ?? null,
              emailgenerated:         outreach.emailgenerated  ?? false,
              emailsent:              emailSent,
              emailskipreason:        emailSent ? null : (outreach.emailskipreason ?? outreach.email_skip_reason ?? null),
              emailsubject:           outreach.emailsubject ?? outreach.email_subject ?? null,
              emailbody:              outreach.emailbody    ?? outreach.email_body    ?? null,
              tools_called:           outreach.tools_called ?? [],
            }
          });
        }
      }
    }
  }
}

return results;
